// TestRegression demonstrates two authentication issues:
// 1. Cookie-based tokens are not supported (only Authorization header)
// 2. No mechanism to skip authentication for specific services
func TestRegression(t *testing.T) {
	authenticator := memory.NewStore()

	// Create a valid client token
	clientToken, storedAuth, err := authenticator.CreateAuthentication(
		context.TODO(),
		&authstorage.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)
	require.NotEmpty(t, clientToken)
	require.NotNil(t, storedAuth)

	logger := zaptest.NewLogger(t)

	t.Run("cookie_based_tokens_are_rejected", func(t *testing.T) {
		// Issue 1: Authentication middleware does not check for cookies
		//
		// Expected: A valid client token stored in a cookie should be accepted
		// Actual: Middleware only looks at "Authorization" header with Bearer format
		//
		// This prevents browser-based sessions from working, since browsers typically
		// store authentication tokens in HTTP cookies, not in the Authorization header.

		// Scenario 1: Token passed via Authorization header (works)
		t.Run("token_via_authorization_header_works", func(t *testing.T) {
			var retrievedCtx context.Context
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				retrievedCtx = ctx
				return nil, nil
			}

			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{
					"authorization": []string{"Bearer " + clientToken},
				},
			)

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)
			assert.NoError(t, err, "Token via Authorization header should be accepted")
			assert.Equal(t, storedAuth, auth.GetAuthenticationFrom(retrievedCtx))
		})

		// Scenario 2: Token passed via cookie header (fails - demonstrates bug)
		t.Run("token_via_cookie_header_fails", func(t *testing.T) {
			var retrievedCtx context.Context
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				retrievedCtx = ctx
				return nil, nil
			}

			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{
					// Simulating a browser cookie header with the client token
					"cookie": []string{"flipt_client_token=" + clientToken},
				},
			)

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// THIS DEMONSTRATES THE BUG:
			// The token is valid, but it's rejected because the middleware
			// only checks the Authorization header, not cookies.
			assert.Error(t, err, "Token via cookie should be accepted but is rejected (BUG)")
			assert.Equal(t, codes.Unauthenticated, status.Code(err))
			assert.Nil(t, auth.GetAuthenticationFrom(retrievedCtx))
		})

		// Scenario 3: Token in custom header (fails - only Authorization header works)
		t.Run("token_via_custom_header_fails", func(t *testing.T) {
			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				return nil, nil
			}

			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{
					// Try passing the token in a custom header
					"x-flipt-token": []string{clientToken},
				},
			)

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// The token is valid, but it's rejected because it's not in the Authorization header
			assert.Error(t, err, "Token via custom header should be accepted but is rejected (BUG)")
			assert.Equal(t, codes.Unauthenticated, status.Code(err))
		})
	})

	t.Run("authentication_service_requires_authentication", func(t *testing.T) {
		// Issue 2: No mechanism to skip authentication for specific services
		//
		// Expected: AuthenticationService methods should be callable without authentication
		//           to allow clients to authenticate themselves
		// Actual: When authentication is enabled, ALL services require authentication,
		//         including the AuthenticationService itself
		//
		// This creates a circular dependency:
		// - To create a token, you need to call CreateToken
		// - But CreateToken requires authentication
		// - But you don't have a token yet to authenticate
		//
		// Additionally, there's no server-level mechanism to configure which
		// services should skip authentication checks.

		authServer := auth.NewServer(logger, authenticator)

		// Test that GetAuthenticationSelf requires authentication
		// when the middleware is applied
		t.Run("auth_service_getauthenticationself_requires_auth", func(t *testing.T) {
			// Try to call GetAuthenticationSelf without authentication
			ctx := context.Background()

			_, err := authServer.GetAuthenticationSelf(ctx, &emptypb.Empty{})

			// THIS DEMONSTRATES THE BUG:
			// The user is not authenticated, and the method correctly returns an error.
			// However, there's no way to call this method WITHOUT authentication,
			// which would be useful for browser-based clients to verify their auth state.
			assert.Error(t, err, "GetAuthenticationSelf requires authentication")

			// The middleware would protect this call, making it impossible to verify
			// if you're authenticated without already being authenticated.
		})

		// Note: We cannot easily test GetAuthenticationSelf with proper authentication context
		// because the authenticationContextKey is unexported. However, the middleware
		// integration tests (middleware_test.go) verify that the context is properly set.
	})

	t.Run("no_server_skip_mechanism", func(t *testing.T) {
		// Issue 3: No mechanism to skip authentication for specific server instances
		//
		// Expected: The gRPC server setup should allow configuring which services
		//           should bypass authentication checks
		// Actual: The UnaryInterceptor is applied globally to all registered services
		//         There's no way to exempt specific services or methods from authentication
		//
		// This is particularly important for services that handle delegated auth flows,
		// such as OAuth callback handlers or token creation endpoints.

		// The authentication middleware is applied at the gRPC server level in main.go:
		//
		//   if cfg.Authentication.Required {
		//       interceptors = append(interceptors, auth.UnaryInterceptor(...))
		//   }
		//   grpcServer = grpc.NewServer(grpc_middleware.WithUnaryServerChain(interceptors...))
		//   pb.RegisterFliptServer(grpcServer, srv)
		//   authrpc.RegisterAuthenticationServiceServer(grpcServer, authServer)
		//
		// This means:
		// 1. ALL registered services go through the auth middleware
		// 2. There's no way to register a service without auth
		// 3. There's no way to skip auth for specific methods

		// Verify that the middleware is applied uniformly
		t.Run("middleware_applied_to_all_methods", func(t *testing.T) {
			// Without authentication in metadata
			ctx := metadata.NewIncomingContext(
				context.Background(),
				metadata.MD{},
			)

			handler := func(ctx context.Context, req interface{}) (interface{}, error) {
				return nil, nil
			}

			_, err := auth.UnaryInterceptor(logger, authenticator)(
				ctx,
				nil,
				nil,
				handler,
			)

			// All methods fail without authentication
			assert.Error(t, err)
			assert.Equal(t, codes.Unauthenticated, status.Code(err))
		})
	})

	t.Run("expired_tokens_are_rejected", func(t *testing.T) {
		// Create an expired token to verify expiration checking still works
		expiredToken, _, err := authenticator.CreateAuthentication(
			context.TODO(),
			&authstorage.CreateAuthenticationRequest{
				Method:    authrpc.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
			},
		)
		require.NoError(t, err)

		ctx := metadata.NewIncomingContext(
			context.Background(),
			metadata.MD{
				"authorization": []string{"Bearer " + expiredToken},
			},
		)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		_, err = auth.UnaryInterceptor(logger, authenticator)(
			ctx,
			nil,
			nil,
			handler,
		)

		// Expired tokens should be rejected
		assert.Error(t, err)
		assert.Equal(t, codes.Unauthenticated, status.Code(err))
	})
}
